import{_ as m,o as g,c as y,a6 as f,cc as b,cd as k,ce as w,cf as v,cg as _,ab as T,ch as C,ci as A,cj as I,ck as P,cl as S,cm as x,c6 as Y,cn as N,co as t,cp as E,cq as i,cr as K,cs as B,ct as M,cu as L,cv as O,cw as n,cx as e,cy as r,cz as l,cA as p,cB as V,cC as c,cD as F,cE as D,cF as W,cG as z,cH as G,cI as R,ad as d,cJ as q,cK as h,cL as U,cM as j,cN as H,cO as $,cP as J,cQ as Q,ah as X,cR as Z,cS as tt,cT as et,dl as at,dm as ot,dn as st,dp as it,dq as nt,dr as rt,ds as lt,dv as pt,dw as ct,dx as dt,dy as ht,dz as ut,dA as mt,dB as gt,dD as yt,dE as a,dH as u,dI as o,dJ as ft,dK as bt,dL as kt}from"./chunks/framework.UYVGz2W_.js";const St=JSON.parse('{"title":"Create an ASSET-only Production","description":"","frontmatter":{},"headers":[],"relativePath":"short-asset/index.md","filePath":"short-asset/index.md"}'),wt={name:"short-asset/index.md"};function vt(_t,s,Tt,Ct,At,It){return g(),y("div",null,[...s[0]||(s[0]=[f('<h1 id="create-an-asset-only-production" tabindex="-1">Create an ASSET-only Production <a class="header-anchor" href="#create-an-asset-only-production" aria-label="Permalink to “Create an ASSET-only Production”">​</a></h1><p>Now that you have designed your workflow in Kitsu and invited more people, it&#39;s time to create your production.</p><p>Click on the <strong>Create a new production</strong> button.</p><p><img src="'+b+'" alt="Create a production"></p><p>Enter your production name, and choose <strong>only Asset</strong> as the <strong>type</strong>, then select the style of your production (2D, 3D).</p><p>Then, you must fill in technical information, such as the number of FPS, the Ration, and the Resolution.</p><p>All these data will be used when Kitsu re-encodes the video previews uploaded.</p><p>Then, you need to define your production&#39;s start and end dates.</p><p><img src="'+k+'" alt="Add a production"></p><p>You can define your production workflow in the next part, 3 to 6.</p><p>You need to select your asset task type (3), task status (4), and asset types (5).</p><p><img src="'+w+'" alt="Add a production Pipeline"></p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>To create your <strong>Production Workflow</strong>, you will select Task Types from the Global Library.</p><p>If you realize you missed some Task Types, you will be able to create them later.</p><p>See the <a href="./../configure-kitsu/index.html#studio-workflows">Studio Workflow</a> section.</p></div><p>Then, 6 is the option part. If you already have a spreadsheet with your Asset.</p><p>See the <strong>import CSV</strong> section for more details.</p><p><a href="#create-an-asset">Import asset</a></p><p>Validate everything with the <img src="'+v+'" alt="All done"> button.</p><h2 id="introduction-to-the-kitsu-global-page" tabindex="-1">Introduction to the Kitsu Global Page <a class="header-anchor" href="#introduction-to-the-kitsu-global-page" aria-label="Permalink to “Introduction to the Kitsu Global Page”">​</a></h2><p>Welcome to Kitsu&#39;s global asset page.</p><p>Let&#39;s take a look around.</p><p><img src="'+_+'" alt="Presentation of the global page"></p><p>On the top part (1), you have the <strong>global navigation</strong>, which is always visible throughout all the production pages.</p><p><strong>From left to right:</strong></p><h3 id="main-menu" tabindex="-1">Main Menu <a class="header-anchor" href="#main-menu" aria-label="Permalink to “Main Menu”">​</a></h3><p>By clicking on the top left button, Kitsu<img src="'+T+'" alt="Main menu button"> (or your Studio logo), you will open the Main Menu.</p><p>On the Main Menu, you will find direct access to your assigned tasks, productions, global and team schedules, the workflow customization page, and the Kitsu settings.</p><details class="details custom-block"><summary>Main Menu Details</summary><p><strong>WORKSPACE</strong></p><ul><li>My Tasks: your assigned tasks</li><li>My Checks: All the tasks with status <strong>Is Feedback Request</strong> depending on your department(s)</li><li>My Productions: Get back to the selection on the production page.</li></ul><p><strong>STUDIO</strong></p><ul><li>Productions</li><li>People</li><li>Timesheets</li><li>Main Schedule</li><li>Team Schedule</li><li>All tasks</li><li>News Feed</li><li>Entity Search</li></ul><p><strong>ADMIN</strong></p><ul><li>Departments</li><li>Task Types</li><li>Asset Types</li><li>Custom Actions</li><li>Automation</li><li>3D Backgrounds</li><li>Bots</li><li>Settings</li><li>Logs</li></ul><div class="warning custom-block"><p class="custom-block-title">Permission Visibility</p><p>The WORKSPACE section is enabled for all permissions except My Checks, which artists do not see.</p><p>Artist (and above) can also see their own <strong>Timesheets</strong>, and have access to the <strong>Entity Search</strong></p></div></details><h3 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to “Navigation”">​</a></h3><p>You will see the navigation dropdown menu on the right of the main menu icon.</p><p><img src="'+C+'" alt="Presentation of the global page"></p><p>You can choose between production. The name of the actual production and actual page are always displayed.</p><p>You can use the dropdown menu to navigate from production to production (if you have several).</p><p>Once you have selected a production, the next dropdown menu will help you navigate through the different pages of this production.</p><details class="details custom-block"><summary>Navigation details</summary><p>The first section is about the tracking of your tasks</p><ul><li>Assets</li><li>Edits (If you have created specific tasks)</li></ul><p>The second section is more about the side of the production</p><ul><li>Concepts</li><li>Breakdown</li><li>Playlists</li><li>News feed</li></ul><p>The third section is about statistics</p><ul><li>Asset Type Stats</li></ul><p>The fourth section is related to Team Management</p><ul><li>Schedule</li><li>Quotas</li><li>Team</li></ul><p>The fifth section is about the settings of your production</p><ul><li>Settings</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You start with the asset page, but you can change your production homepage to other entities (see setting page)</p></div></details><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>If you realize you need an extra level of navigation, such as <strong>Episodes</strong>, you need to change your production Type to a <strong>TV Show</strong>.</p><p>If, on the contrary, you realize you need the <strong>shots</strong>, you also need to switch your production type from <strong>Only Assets</strong> to <strong>Short</strong>.</p></div><h3 id="global-search-news-notification-and-documentation" tabindex="-1">Global Search, News, Notification and Documentation <a class="header-anchor" href="#global-search-news-notification-and-documentation" aria-label="Permalink to “Global Search, News, Notification and Documentation”">​</a></h3><p>You have the global search on the right of the navigation dropdown menu. It&#39;s a quick access search that will display the four first results. If you need more results and filtering options, see the <strong>Entity Search</strong> page.</p><p>The next icon <img src="'+A+'" alt="News"> is a direct link to our news and feedback page.</p><p>You can see all the new features with an animated gif and also add suggestions about the next feature you want to see in Kitsu.</p><p>Next, the bell icon <img src="'+I+'" alt="Notification"> displays your notifications (assignments, comments, tags). The number of unread notifications will be shown on the bell icon. There are various filters to help you stay on top of updates and revisit important ones when needed. You can easily mark notifications as read or unread or quickly filter by watching/non-watching to focus on what matters most and declutter your feed.</p><p>The last icon before your avatar is the documentation button. <img src="'+P+'" alt="documentation button">, that you are reading right now!</p><h3 id="personal-settings" tabindex="-1">Personal Settings <a class="header-anchor" href="#personal-settings" aria-label="Permalink to “Personal Settings”">​</a></h3><p>You can click on your avatar to open your menu (setting, documentation, etc.).</p><p><img src="'+S+'" alt="Profile enlarged">.</p><h2 id="the-tasks-spreadsheet" tabindex="-1">The Tasks Spreadsheet <a class="header-anchor" href="#the-tasks-spreadsheet" aria-label="Permalink to “The Tasks Spreadsheet”">​</a></h2><h3 id="entity-spreadsheet" tabindex="-1">Entity spreadsheet <a class="header-anchor" href="#entity-spreadsheet" aria-label="Permalink to “Entity spreadsheet”">​</a></h3><p>The second part of the screen is common to all the entities (Asset, shot, sequence, Edit). This is the global tasks spreadsheet.</p><p>Here, you see the status, assignation, priority, etc, for each task.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The first line and column header of the spreadsheet always appear at the top of the page, even if you scroll down.</p><p>You can also <strong>Stick</strong> other columns to keep them visible at all times.</p></div><h3 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to “Filters”">​</a></h3><p>The first element on the left is the filter box. You can type anything you want for simple filtering, sequence, asset type, etc.</p><p>If you need more advanced filtering, please use the filter builder button.</p><p><img src="'+x+'" alt="Filter Builder"></p><p>You can then save all the filters and use them as your pages.</p><h3 id="simplify-the-display" tabindex="-1">Simplify the display <a class="header-anchor" href="#simplify-the-display" aria-label="Permalink to “Simplify the display”">​</a></h3><p>On the right part of the screen, there are some buttons (from left to right) to hide or display the assignation, hide or display the extra column, enlarge or reduce the thumbnail, <img src="'+Y+'" alt="display and Hide option"></p><h3 id="import-export" tabindex="-1">Import / Export <a class="header-anchor" href="#import-export" aria-label="Permalink to “Import / Export”">​</a></h3><p>batch import thumbnail <img src="'+N+'" alt="batch import thumbnail">, and finally import <img src="'+t+'" alt="Import button"> or export <img src="'+E+'" alt="export button"> data.</p><h3 id="metadata-column" tabindex="-1">Metadata column <a class="header-anchor" href="#metadata-column" aria-label="Permalink to “Metadata column”">​</a></h3><p>Below, you have the name of the column. the (+) next to <strong>Name</strong> <img src="'+i+'" alt="Add metadata column"> is here to create a new metadata column. Then, you have the name of the task type column.</p><h3 id="customize-the-view" tabindex="-1">Customize the view <a class="header-anchor" href="#customize-the-view" aria-label="Permalink to “Customize the view”">​</a></h3><p>On the far right of the screen, next to the scroll bar, is the option to hide and display a text column</p><p><img src="'+K+'" alt="Display/hide text column">.</p><h3 id="sum-up-of-your-view" tabindex="-1">Sum-up of your view <a class="header-anchor" href="#sum-up-of-your-view" aria-label="Permalink to “Sum-up of your view”">​</a></h3><p>The last part (4), at the bottom of the screen, is the sum-up of your displayed page. It means the sum-up will update if you filter the page.</p><p>You can see the number of elements (assets or shots), the total number of estimated days, and the total number of days already spent.</p><h2 id="create-an-asset" tabindex="-1">Create an Asset <a class="header-anchor" href="#create-an-asset" aria-label="Permalink to “Create an Asset”">​</a></h2><h3 id="create-your-first-asset" tabindex="-1">Create your first Asset <a class="header-anchor" href="#create-your-first-asset" aria-label="Permalink to “Create your first Asset”">​</a></h3><p>So, now that we have created our production and have a general grasp of the Kitsu interface, it&#39;s time to create our very first Asset.</p><p>On the asset page, click on <strong>Add assets</strong>.</p><p><img src="'+B+'" alt="Asset page first time"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>When you create an asset, your task workflow will be applied, and <strong>all the tasks will be created simultaneously as the Asset</strong>.</p></div><p>A pop-up window opens:</p><p>It asks you to choose the <strong>Asset Type</strong> (1). If you didn&#39;t add a new asset type, Kitsu will provide you with examples such as Characters, Environment, FX, Props, etc. Let&#39;s start with a character.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can also customize the asset type list and the tasks pipeline. See the guide ( <a href="./../configure-kitsu/index.html#asset-types">Customization of the workflow</a>) for more details</p></div><p>We give it a <strong>Name</strong> (2) and enter a description that helps the Artist know what to do and quickly identify the Asset.</p><p>Click on <strong>Confirm and stay</strong> if you have multiple assets to create.</p><p><img src="'+M+'" alt="Create an asset"></p><p>You can change the asset type and keep adding assets.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The newly created Asset appears in the background whenever you click on <strong>Confirm and stay</strong>.</p></div><p>After adding your last Asset, click on <strong>Confirm</strong>. It will create the Asset and close the window.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>If you click on **Confirm and stay ** but realize you don&#39;t have more assets to add, click on <strong>Close</strong>, and the winwill bew is canceled.</p></div><p><img src="'+L+'" alt="Global asset page"></p><p>You will also see the tasks that are selected for your assets workflow are created at the same time.</p><p>If you need to add more <strong>Assets</strong>, click the <strong>+ Create assets</strong> button.</p><details class="details custom-block"><summary>Create Assets from a CSV Spreadsheet File</summary><p>You may already have your asset list ready in a spreadsheet file. With Kitsu, you have two ways to import them; the first is to import a <code>.csv</code> file and copy-paste your data directly into Kitsu.</p><p>First, save your spreadsheet as a <code>.csv</code> file.</p><p>Then, go back to the asset page on Kitsu and click on the <strong>Import</strong> icon. <img src="'+t+'" alt="Import Icon"></p><p>A pop-up window <strong>Import data from a CSV</strong> opens. Click on <strong>Browse</strong> to pick your <code>.csv</code> file.</p><p><img src="'+O+'" alt="Import csv file"></p><p>To see the result, click on the <strong>Preview</strong> button.   You can check and adjust the name of the columns by previewing your data.   NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.   <img src="'+n+'" alt="Import data copy paste data"></p><p>Once everything is good, click the <strong>Confirm</strong> button to import your data into Kitsu.</p><p>Now, you have imported all your assets into Kitsu and created the task according to your Settings.</p><p><img src="'+e+'" alt="Import data copy paste data"></p></details><details class="details custom-block"><summary>Create Assets by Copying / Pasting a Spreadsheet File</summary><p>Open your spreadsheet, select your data, and copy them.</p><p><img src="'+r+'" alt="Import copy data"></p><p>Then, go back to the asset page on Kitsu and click on the <strong>Import</strong> icon <img src="'+t+'" alt="Import Icon">.</p><p>A pop-up window <strong>Import data from a CSV</strong> opens; click on the <strong>Paste a CSV data</strong> tab.</p><p><img src="'+l+'" alt="Import data copy paste tab">   You can paste your previously selected data and see the result with the <strong>Preview</strong> button.   <img src="'+p+'" alt="Import data copy paste data">   You can check and adjust the name of the columns by previewing your data.   NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.   <img src="'+n+'" alt="Import data copy paste data"></p><p>Once everything is good, click the <strong>Confirm</strong> button to import your data into Kitsu.</p><p>Now, you have imported all your assets into Kitsu and created the task according to your Settings.</p><p><img src="'+e+'" alt="Import data copy paste data"></p></details><h3 id="see-the-details-of-an-asset" tabindex="-1">See the Details of an Asset <a class="header-anchor" href="#see-the-details-of-an-asset" aria-label="Permalink to “See the Details of an Asset”">​</a></h3><p>To see an asset&#39;s detail, click on its name.</p><p><img src="'+V+'" alt="Asset detail"></p><p>A new page opens with the list of the tasks, the assignation, and the status newsfeed on the right.</p><p><img src="'+c+'" alt="Asset detail page"></p><p>You can click on the status of each task to open the comment panel and see the history of the comments and the different versions.</p><p><img src="'+F+'" alt="Asset detail page"></p><p>You can also access the <strong>Casting</strong>,</p><p><img src="'+D+'" alt="Asset detail casting"></p><p><strong>concept</strong> linked to this Asset,</p><p><img src="'+W+'" alt="Asset detail casting"></p><p>The <strong>Schedule</strong> is available if you have previously filled out the task type page data. If the data have already been filled out, you will be able to modify them directly here.</p><p><img src="'+z+'" alt="Asset detail casting"></p><p>the <strong>Preview Files</strong> uploaded at various task types,</p><p><img src="'+G+'" alt="Asset detail casting"></p><p>And the <strong>Timelog</strong> if people have filled out their timesheet on the tasks of this Asset.</p><p><img src="'+R+'" alt="Asset detail casting"></p><h2 id="add-more-tasks-after-creating-the-assets" tabindex="-1">Add more tasks after creating the assets <a class="header-anchor" href="#add-more-tasks-after-creating-the-assets" aria-label="Permalink to “Add more tasks after creating the assets”">​</a></h2><p>If you realize <strong>after</strong> creating the assets that the task is missing, you can still add them.</p><p>First, be sure that the missing task type is added to the settings page under the task type tab.</p><p>Then go back to the asset page and click on <strong>+ Add tasks</strong></p><p>### Update your assets At any point, you can update your assets, change their name and asset type, modify their description, and any custom information you added to the global page.</p><p>You can edit assets by going to the asset page, hovering over the Asset you want to modify, and then clicking on the <strong>edit</strong> button <img src="'+d+'" alt="Edit button"> (1) on the right side of the line.</p><p><img src="'+q+'" alt="Edit an asset"></p><p>To extend the description on the main asset page, click on the first words (2), and a pop-up with the full description will open.</p><details class="details custom-block"><summary>Update Assets with the CSV Import</summary><p>You can use the CSV import to update your data quickly.</p><p>You can update the <strong>type</strong> of an asset, the <strong>Assignation</strong>, the <strong>Status</strong> of tasks, and add a <strong>Comment</strong>.</p><p>You need to switch on the option <strong>Update existing data</strong>. Then the lines that will be updated will be highlighted in blue.</p><p><img src="'+h+'" alt="Import data copy paste data"></p></details><details class="details custom-block"><summary>Update Assets by Copying / Pasting a Spreadsheet File</summary><p>Open your spreadsheet, select your data, and copy them.</p><p><img src="'+r+'" alt="Import copy data"></p><p>Then, go back to the asset page on Kitsu and click on the <strong>Import</strong> icon <img src="'+t+'" alt="Import Icon">.</p><p>A pop-up window <strong>Import data from a CSV</strong> opens; click on the <strong>Paste a CSV data</strong> tab.</p><p><img src="'+l+'" alt="Import data copy paste tab">   You can paste your previously selected data and see the result with the <strong>Preview</strong> button.   <img src="'+p+'" alt="Import data copy paste data">   You can check and adjust the name of the columns by previewing your data.</p><p>NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.   You need to switch on the option <strong>Update existing data</strong>. Then, the lines that will be updated will be highlighted in blue.</p><p><img src="'+h+'" alt="Import data copy paste data"></p><p>Now, you have imported all your assets into Kitsu and created the task according to your Settings.</p><p><img src="'+e+'" alt="Import data copy paste data"></p></details><h2 id="create-a-concept" tabindex="-1">Create a Concept <a class="header-anchor" href="#create-a-concept" aria-label="Permalink to “Create a Concept”">​</a></h2><h3 id="upload-a-concept" tabindex="-1">Upload a Concept <a class="header-anchor" href="#upload-a-concept" aria-label="Permalink to “Upload a Concept”">​</a></h3><p>To create a <strong>Concept</strong>, go to the <strong>Concept</strong> page with the navigation menu.</p><p><img src="'+U+'" alt="Concept Menu"></p><p>To upload a concept, click the <strong>Add a new reference to concepts</strong> button.</p><p>You can upload one or several concepts at the same time.</p><p><img src="'+j+'" alt="Concept empty page"></p><p>Once you upload your previews, the concept page will look like this.</p><p><img src="'+H+'" alt="Concept filled page"></p><p>You can interact with the concept in two ways: click on the picture to see an enlarged view. The second is to click on the status part to open the <strong>Comment Panel</strong> on the right.</p><p>On the comment panel, you have two options: link a concept to an existing asset or delete it. You can also comment and change the status of the Asset.</p><p>The idea is to have one version per <strong>Concept</strong>. If it&#39;s not approved, you need to upload a new concept, not to have multiple versions of the same concept.</p><p>One concept is one task.</p><p><img src="'+$+'" alt="Concept options"></p><h3 id="link-a-concept-to-an-asset" tabindex="-1">Link a Concept to an Asset <a class="header-anchor" href="#link-a-concept-to-an-asset" aria-label="Permalink to “Link a Concept to an Asset”">​</a></h3><p>Once concepts are uploaded, you can link them to the assets.</p><p>You can see the links on the status part of the assets.</p><p>Click on the status part of the concept; it will open the comment panel on the right.</p><p><img src="'+J+'" alt="Concept Comment Panel"></p><p>On the comment panel, you have two options at the top: Link a concept to an asset and delete the concept.</p><p>To link an asset, click on the <strong>Link</strong> <img src="'+Q+'" alt="Link button"> button.</p><p>Kitsu will display all the <strong>Assets</strong> available to link with the concept uploaded.</p><p>Kitsu will list the linked assets at the top of the comment panel. For now, there are No Links.</p><p><img src="'+X+'" alt="Concept link"></p><p>To link an asset, you have to click on it. The linked assets&#39; names will appear at the top of the screen and under the preview of the concept.</p><p><img src="'+Z+'" alt="Concept asset linked"></p><p>Once a concept is linked to an asset, it can be seen on the asset&#39;s detail page.</p><p>Return to the asset page, and click on the asset name you want to see the concept.</p><p><img src="'+c+'" alt="Detail asset page"></p><p>Per default, the casting detail is displayed on the second part of the screen. Use the dropdown menu to choose the concept.</p><p><img src="'+tt+'" alt="asset detail concept"></p><p>Once in the concept section, you will see all the concepts created for this Asset. You can filter them per status.</p><p><img src="'+et+'" alt="asset detail concept list"></p><h2 id="create-custom-metadata-columns" tabindex="-1">Create Custom Metadata Columns <a class="header-anchor" href="#create-custom-metadata-columns" aria-label="Permalink to “Create Custom Metadata Columns”">​</a></h2><p>To add more information on the general spreadsheet pages, you must create a custom <strong>metadata column</strong>.</p><p>You may have extra information to add to your pages, such as the <strong>level of difficulties</strong>, <strong>Weather</strong>, <strong>Tag</strong>, etc. You can store all text (or number) information in the custom metadata column.</p><p>Click on the <strong>+</strong> near the Name column.</p><p><img src="'+i+'" alt="Metadata Column"></p><p>With the <strong>Type</strong> option, you can choose how you want to store your information:</p><ul><li>a free <strong>Text</strong>,</li><li>a <strong>Number</strong>,</li><li>a <strong>Checkbox</strong>,</li><li>a <strong>List of value</strong>,</li><li>a <strong>List of tags</strong>,</li><li>a <strong>Checklist</strong>.</li></ul><p><img src="'+at+'" alt="Metadata Column detail"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>The <strong>Text</strong>, <strong>Number</strong>, and <strong>Checkbox</strong> allow you to add different information for each entity. You don&#39;t have to plan it first.</p><p>The <strong>List of value</strong>, <strong>List of tags</strong>, and <strong>Checklist</strong> give you the same choice for each entity. Moreover, it has to be filled now.</p><p><img src="'+ot+'" alt="Metadata Column list"></p><p>Type the list elements below <strong>Available values</strong>, and confirm them by clicking on <strong>Add value</strong>.</p></div><p>You can also link the <strong>metadata column</strong> to one or several <strong>departments</strong>.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Link a metadata column to a department. The artists/supervisors will see it on their to-do page and in the department-filtered view.</p><p>You can link the metadata column to one or more departments. Click on the department from the list and then click on <strong>add</strong> to be effective.</p><p>Here, the VFX column is linked to two departments.</p><p><img src="'+st+'" alt="Department metadata column filtered view"></p></div><details class="details custom-block"><summary>Edit meta column</summary><p>On the global page of the Asset or the shot, click on the arrow to the right of your metadata column and click on <strong>Edit</strong>.</p><p><img src="'+it+'" alt="Metadata column Edit"></p></details><p>You can fill in this information directly on the global spreadsheets page. The cases are editable.</p><p><img src="'+nt+'" alt="Metadata Column detail"></p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can batch-modify the metadata column by selecting several entities on the left and then modifying your metadata column.</p></div><details class="details custom-block"><summary>Edit by hand</summary><p>You can also modify the information with the edit button <img src="'+d+'" alt="Edit button">.</p><p>You now see a new line on the edit pop-up. You can select the information from the list, alternatively, enter the free text or number, check a box, or use the checklist, depending on your previous choice.</p><p>Remember to press the <strong>Confirm</strong> button when you are done.</p><p><img src="'+rt+'" alt="Metadata Column detail"></p></details><p>Go to the general spreadsheet page if you need to edit or delete the metadata column. Nearby the name of your metadata column, click on the arrow <img src="'+lt+'" alt="Metadata Column detail">.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can <strong>sort</strong> your global page with this new column. Click the arrow on the right of the column name to open his menu. Then click on <strong>Sort By</strong>.</p><p>You can also <strong>Stick</strong> the metadata column to the left.</p></div><h2 id="create-an-edit" tabindex="-1">Create an Edit <a class="header-anchor" href="#create-an-edit" aria-label="Permalink to “Create an Edit”">​</a></h2><p>You can track tasks at the <strong>Edit</strong> Level in Kitsu.</p><p>It&#39;s especially useful when You have several edits to track through several validation steps. For example, you can track your whole movie, several trailers, and the First Edit, Fine Edit, Mix, etc.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Per default, the <strong>Edit</strong> page will not be displayed until you have task types for it on your <strong>production library</strong> (setting page)</p></div><p>To use this page, you need to first create a dedicated task type on your <strong>Global Library</strong>  with the <strong>Edit</strong> attribute.</p><p>See the <strong>Creating a New Task Type</strong> Section to create a new <strong>Task Type</strong>.</p><p><a href="./../configure-kitsu/index.html#task-types">Creating a New Task Type</a></p><p>Once you have created your <strong>Task Types</strong>  on your <strong>Global Library</strong>, add them to your <strong>Production Library</strong>, you will see the <strong>Edit</strong> displayed on the navigation drop-down menu.</p><p><img src="'+pt+'" alt="Navigation Edit"></p><p>This new page behaves like the Asset and Shot global page. You can add your edits with the <strong>+ New edit</strong> button.</p><p>You can assign tasks, do the review, change status, etc.</p><p>You can add a metadata column, fill in the description, etc.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Depending on your deliveries, you can also change the resolution per <strong>Edit</strong>.</p></div><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>The detail page is different from the other entities.</p><p>As <strong>Edit</strong> focuses on a specific long video, the detail page looks more like the comment detail page.</p></div><p>You can <strong>Rename</strong> and <strong>Delete</strong> the Edit entity on this page, as you can for the Asset and shot entities.</p><h2 id="create-a-breakdown-list" tabindex="-1">Create a Breakdown List <a class="header-anchor" href="#create-a-breakdown-list" aria-label="Permalink to “Create a Breakdown List”">​</a></h2><p>Filling out the breakdown helps you with the assembly of the Asset. With the breakdown, you have all the details of the assets you need to add to create your main Asset and we are sure we will omit nothing.</p><p>On the dropdown menu, choose <strong>BREAKDOWN</strong>.</p><p><img src="'+ct+'" alt="drop down Menu breakdown"></p><p>On the left of the breakdown page is the asset menu (1); you can choose between those you created. They are the right part of the screen; all the assets created are available for this production (3). Moreover, in the middle section, your selection for the Asset (2).</p><p><img src="'+dt+'" alt="Breakdown page"></p><p>So now you have to select the Asset you want to cast.</p><p>You can display the assets as text if you don&#39;t have thumbnails yet or enlarge the thumbnails size.</p><p><img src="'+ht+'" alt="Breakdown page text display"></p><p>You may also realize an asset needs to be added to the list during your breakdown.</p><p>You can create a new asset directly from the breakdown page. Click the <strong>+</strong> on the right of the <strong>All available assets</strong>.</p><p><img src="'+ut+'" alt="Breakdown page create asset"></p><p>You can also select multiple assets at once. Click on the first Asset, hold the <strong>shift</strong> key, and click on the last Asset of your selection.</p><p><img src="'+mt+'" alt="Breakdown page global bulk select"></p><p>Then click on the assets you want to assign: characters, backgrounds, ... from the right part (3). If you have selected multiple assets, your selection is applied to the numerous assets.</p><p>Copy an asset filled with assets and paste this asset selection into another asset.</p><p>You can see a <strong>+1</strong> or <strong>+10</strong> when you pass over the Asset. It&#39;s the number of times you add this Asset, and you can click on it as many times as you need.</p><p><img src="'+gt+'" alt="Breakdown add asset"></p><p>You can now see the Asset in the middle of the screen (2). Next to the Asset&#39;s name is the number of times it has been added. In this example, we have added the character asset Llama two times.</p><p>If you add an asset twice by mistake, you must go to the screen&#39;s middle part to select assets for this shot (2). From there, click on <strong>-1</strong>. When you finish this shot, go on with the other shots. Your selection is automatically saved.</p><p><img src="'+yt+'" alt="Breakdown remove asset"></p><p>If a new asset is created during the task, return to the asset page (using the dropdown menu) and create the needed assets. The tasks previously created are applied immediately to these new assets. However, you have to do the assignment, and then you can continue with the breakdown.</p><p>Now, your <strong>Breakdown</strong> page should look like this.</p><p><img src="'+a+'" alt="breakdown add asset bulk"></p><details class="details custom-block"><summary>Create a Breakdown List from a CSV File</summary><p>You may already have your breakdown list ready in a spreadsheet file. With Kitsu, you have two ways to import it: the first is to import a .csv file directly, and the second is to copy-paste your data directly into Kitsu.</p><p>First, save your spreadsheet as a <code>.csv</code> file following Kitsu&#39;s recommendation.</p><p>Click on the <strong>import</strong> button <img src="'+t+'" alt="Import button"></p><p>A pop-up window <strong>Import data from a CSV</strong> opens. Click on <strong>Browse</strong> to pick your <code>.csv</code> file.</p><p><img src="'+u+'" alt="Breakdown import csv file"></p><p>To see the result, click on the <strong>Preview</strong> button.</p><p>You can check and adjust the name of the columns by previewing your data.</p><p>NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.</p><p><img src="'+o+'" alt="Breakdown import Preview"></p><p>Once everything is good, click the <strong>Confirm</strong> button to import your data into Kitsu.</p><p>Now, you have your breakdown imported into Kitsu.</p><p><img src="'+a+'" alt="Breakdown import Preview"></p></details><details class="details custom-block"><summary>Create a Breakdown List by Copying / Pasting a Spreadsheet File</summary><p>Open your spreadsheet, select your data, and copy them.</p><p><img src="'+ft+'" alt="Import copy data"></p><p>Then, go back to the breakdown page on Kitsu, and click on the <strong>Import</strong> icon <img src="'+t+'" alt="Import Icon">.</p><p>A pop-up window <strong>Import data from a CSV</strong> opens; click on the <strong>Paste a CSV data</strong> tab.</p><p><img src="'+u+'" alt="Import data copy paste tab">   You can paste your previously selected data and see the result with the <strong>Preview</strong> button.   <img src="'+o+'" alt="Import data copy paste data">   You can check and adjust the name of the columns by previewing your data.   NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.   <img src="'+o+'" alt="Import data copy paste data"></p><p>Once everything is good, click the <strong>Confirm</strong> button to import your data into Kitsu.</p><p>Now, all your assets have been imported into Kitsu.</p><p><img src="'+a+'" alt="Import data copy paste data"></p></details><h2 id="casting-from-the-asset-library" tabindex="-1">Casting from the Asset Library <a class="header-anchor" href="#casting-from-the-asset-library" aria-label="Permalink to “Casting from the Asset Library”">​</a></h2><p>It is also possible to cast assets from the global <strong>Asset Library</strong> into your production. This allows you to cast an already existing asset, without the need to re-create it for each production.</p><p><img src="'+bt+'" alt="Asset Library Display"></p><p>To see assets outside of your production from the asset library, click the <strong>Display Library</strong> Button (1)</p><p>Assets from the global asset library will appear, and will be highlighted with a yellow boarder (2). They can then be cast in your breakdown exactly the same as other assets.</p><p><img src="'+kt+'" alt="Asset Library View"></p><p>Back on your productions asset page, you can choose to display global assets that have been cast in your production by toggling the <strong>Display Library</strong> button (1). These assets will be highlighted in yellow, indicating that they originate from the global asset library, and not your current production. (2).</p>',213)])])}const xt=m(wt,[["render",vt]]);export{St as __pageData,xt as default};
